import{_ as t,o as l,c as i,ag as e}from"./chunks/framework.DXGyWiRo.js";const r="/media/202601//1767854989.498279.png",d="/media/202601//1767854989.5029979.png",o="/media/202601//1767854989.5059571.png",n="/media/202601//1767854989.5097992.png",p="/media/202601//1767854989.5130134.png",s="/media/202601//1767854989.516532.png",h="/media/202601//1767854989.519739.png",c="/media/202601//1767854989.5229933.png",m="/media/202601//1767854989.525652.png",u="/media/202601//1767854989.5277174.png",b="/media/202601//1767854989.530977.png",g="/media/202601//1767854989.5345187.png",f="/media/202601//1767854989.5377152.png",_="/media/202601//1767854989.5413775.png",q="/media/202601//1767854989.5432415.png",k="/media/202601//1767854989.5450082.png",x="/media/202601//1767854989.5476017.png",P="/media/202601//1767854989.5495174.png",I="/media/202601//1767854989.5553567.png",A="/media/202601//1767854989.5574262.png",v=JSON.parse('{"title":"RK3588S 多模态套件使用手册","description":"","frontmatter":{"title":"RK3588S 多模态套件使用手册"},"headers":[],"relativePath":"hardware/rk3588s-mm/manual.md","filePath":"hardware/rk3588s-mm/manual.md","lastUpdated":null}'),S={name:"hardware/rk3588s-mm/manual.md"};function w(U,a,y,B,E,z){return l(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h1><ol><li>产品概述 1.1编写目的 1.2 技术简介 1.3 主要应用场景 1.4 套件清单</li><li>硬件介绍与安装 2.1硬件实物图 2.2 麦克风实物检查 2.3 接线实物图</li><li>体验准备与说明 3.1 开机与系统初始化 3.2 配置网络</li><li>功能详解 4.1 可视化交互界面说明 4.2 标准使用模式 4.3 扩展使用方式说明</li><li>高级配置与开发 5.1 Appid申请与配置 5.2 协议对接 5.3 二次开发指南</li><li>调试与故障排除 6.1日志获取与分析 6.2获取本地音频、图像 6.3常见问题汇总</li><li>附录</li></ol><h1 id="离线资料下载" tabindex="-1">离线资料下载 <a class="header-anchor" href="#离线资料下载" aria-label="Permalink to &quot;离线资料下载&quot;">​</a></h1><p>RK3588S 多模态套件开发资料（产品白皮书、使用手册、规格书），可以点击下载: <a href="/media/attachment/2026/03/RK3588S%E9%80%9A%E7%94%A8%E5%A4%9A%E6%A8%A1%E6%80%81%E5%A5%97%E4%BB%B6%E5%BC%80%E5%8F%91%E8%B5%84%E6%96%99.zip">【附件】RK3588S通用多模态套件开发资料.zip</a></p><h2 id="产品概述" tabindex="-1">产品概述 <a class="header-anchor" href="#产品概述" aria-label="Permalink to &quot;产品概述&quot;">​</a></h2><h2 id="编写目的" tabindex="-1">编写目的 <a class="header-anchor" href="#编写目的" aria-label="Permalink to &quot;编写目的&quot;">​</a></h2><p>本文档主要为了让客户快速接入极简通用多模态套件。</p><h2 id="技术简介" tabindex="-1">技术简介 <a class="header-anchor" href="#技术简介" aria-label="Permalink to &quot;技术简介&quot;">​</a></h2><p>多模态降噪技术通过融合视觉与声学信息实现高效降噪，其工作原理是：系统通过检测人脸打开唤醒状态，将唇形跟语音信息作为起始和结束信号来控制拾音过程；在锁定主讲人后，系统分析唇动信息处理高噪声环境下的音频，再将优化后的音频上传至云端进行识别。这一技术方案能够有效提升高噪环境中的语音交互准确性和鲁棒性。</p><h2 id="主要应用场景" tabindex="-1">主要应用场景 <a class="header-anchor" href="#主要应用场景" aria-label="Permalink to &quot;主要应用场景&quot;">​</a></h2><ul><li>**智慧政务一体机：**提供免接触、高效率的业务查询与办理体验。</li><li>**医疗自助挂号机：**通过人脸与语音交互，简化就诊流程，保护患者隐私。</li><li>**交通枢纽购票机：**在嘈杂环境中精准识别用户指令，快速完成票务购买。</li><li>**商业虚拟人交互大屏：**主动吸引顾客注意，实现精准营销与互动导览。</li><li>**工业调度大屏：**解放双手，通过语音指令实时查询与操控生产信息。</li></ul><h2 id="套件清单" tabindex="-1">套件清单 <a class="header-anchor" href="#套件清单" aria-label="Permalink to &quot;套件清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>序号</strong></td><td><strong>硬件名称</strong></td><td><strong>数量</strong></td><td><strong>说明</strong></td></tr><tr><td>1</td><td>3588s主板</td><td>1</td><td>默认无外壳，选配带外壳主机</td></tr><tr><td>2</td><td>500W摄像头</td><td>1</td><td>摄像头焦距3.3mm，支持0.5米到1.9米内交互 默认裸件，选配带结构件外壳</td></tr><tr><td>3</td><td>声卡麦板二合一板</td><td>1</td><td></td></tr><tr><td>4</td><td>电源适配器</td><td>1</td><td>长度1.5米，航嘉电源适配器</td></tr><tr><td>5</td><td>USB线束</td><td>1</td><td>长度2.5米，4pinUSB2.0转4pinUSB2.0线束</td></tr><tr><td>6</td><td>摄像头线束</td><td>1</td><td>长度5.6cm，4pinUSB2.0转4pinUSB2.0线束</td></tr><tr><td>7</td><td>回采线</td><td>1</td><td>长度2.5米，5pin转3.5mm耳机口</td></tr><tr><td>8</td><td>串口线</td><td>1</td><td>主板：1米，4pin ttl接口转USB串口线 主机：1米，4pin 232接口转USB串口线</td></tr><tr><td>9</td><td>天线</td><td>1</td><td>主板：12cm天线 主机：12cm胶棒天线</td></tr></tbody></table><p>表1 通用多模态套件清单</p><h1 id="硬件介绍与安装" tabindex="-1">硬件介绍与安装 <a class="header-anchor" href="#硬件介绍与安装" aria-label="Permalink to &quot;硬件介绍与安装&quot;">​</a></h1><h2 id="硬件实物图" tabindex="-1">硬件实物图 <a class="header-anchor" href="#硬件实物图" aria-label="Permalink to &quot;硬件实物图&quot;">​</a></h2><p><img src="'+r+'" alt="" title="null"></p><p>图1 通用多模态四麦单目远焦配件硬件内容图</p><h2 id="麦克风实物检查" tabindex="-1">麦克风实物检查 <a class="header-anchor" href="#麦克风实物检查" aria-label="Permalink to &quot;麦克风实物检查&quot;">​</a></h2><p><img src="'+d+'" alt="" title="null"></p><p>图2 麦克风正面图</p><ul><li>若麦克风有密封贴请撕下所有密封贴，确保麦克风板孔如上图无遮挡。</li><li>麦克风正面朝向人收音。</li></ul><h2 id="接线实物图" tabindex="-1">接线实物图 <a class="header-anchor" href="#接线实物图" aria-label="Permalink to &quot;接线实物图&quot;">​</a></h2><p><img src="'+o+'" alt="0f7862f2c29dc768f9a0f5c90edcb355" title="null"></p><p>图3 通用多模态套件裸板实物接线图</p><ol><li>为保障Wi-Fi连接质量，请先插上天线；</li><li>使用4pin转4pin音视频线束连接四麦声卡板和3588s主板，获取音视频信号；</li><li>使用4pin转3.5mm耳机口线束，一端连接声卡板的‘回采接口’，另一端连接3588s主板的3.5mm耳机输出口，用于采集设备自身播放的音频以实现回声消除；（如使用外置功放，回采从外置功放接回四麦声卡板）；</li><li>使用HDMI线束连接3588s主板跟显示屏，连接无线网络及体验多模态demo；</li><li>插上电源；</li><li>正式组装时，最好将摄像头放在麦克风板中间的孔洞中，保障最佳使用效果。</li><li><strong>注意：请确保在断电情况下进行连接操作。</strong></li></ol><p><img src="'+n+'" alt="0a94eeb48458e5d118a4c3e58b13b483" title="null"></p><p>图4 通用多模态套件带外壳反面接线图</p><p><img src="'+p+'" alt="a56bbd4338e24711e60a001cf844d7ae" title="null"></p><p>图5 通用多模态套件带外壳正面接线图</p><p>可按照图示顺序接线。</p><h1 id="体验准备与说明" tabindex="-1">体验准备与说明 <a class="header-anchor" href="#体验准备与说明" aria-label="Permalink to &quot;体验准备与说明&quot;">​</a></h1><h2 id="_3-1开机与系统初始化" tabindex="-1">3.1开机与系统初始化 <a class="header-anchor" href="#_3-1开机与系统初始化" aria-label="Permalink to &quot;3.1开机与系统初始化&quot;">​</a></h2><p><strong>准备条件：</strong> 需要可连接HDMI的显示器</p><ul><li>连接主板的HDMI接口以及显示的HDMI接口。</li></ul><p><img src="'+s+'" alt="3b0e137debd95bea8de934f16d52b7e8" title="null"></p><p>图6 hdmi接线图</p><ul><li>接上电源等待设备启动完成，启动完成后如下图。</li></ul><p><img src="'+h+'" alt="" title="null"></p><p>图7 3588s系统launcher图</p><ul><li>接入鼠标或使用触屏 “<strong>向上滑动</strong>”，进入系统应用界面。</li></ul><p><img src="'+c+'" alt="" title="null"></p><p>图8 3588s应用界面图</p><h2 id="配置网络" tabindex="-1">配置网络 <a class="header-anchor" href="#配置网络" aria-label="Permalink to &quot;配置网络&quot;">​</a></h2><ul><li><strong>wifi模式：</strong> 点击界面中的 设置—-网络与互联网—-互联网—-选择wifi输入密码连接wifi</li><li><strong>有线网络模式：</strong> 直接将网线插入到3588s主板的网口中</li></ul><h2 id="启动多模态应用" tabindex="-1">启动多模态应用 <a class="header-anchor" href="#启动多模态应用" aria-label="Permalink to &quot;启动多模态应用&quot;">​</a></h2><ul><li>点击应用界面的《多模态应用》程序</li></ul><p><img src="'+m+'" alt="826829101f26ae8b6147190760020f82" title="null"></p><p>图9 多模态套件应用界面</p><ul><li>进入可视化交互界面</li></ul><p><img src="'+u+'" alt="00e8be7aee4081b06f8b09c6ddde2d93" title="null"></p><p>图10 多模态应用可视化预览界面</p><h1 id="四-功能详解" tabindex="-1">四．功能详解 <a class="header-anchor" href="#四-功能详解" aria-label="Permalink to &quot;四．功能详解&quot;">​</a></h1><h2 id="可视化交互界面说明" tabindex="-1">可视化交互界面说明 <a class="header-anchor" href="#可视化交互界面说明" aria-label="Permalink to &quot;可视化交互界面说明&quot;">​</a></h2><ol><li><p>可视化交互界面下，左侧为人脸视觉信号识别展示区域，当人脸出现在左侧图像中，并人脸有绿框选中，可开始交互；当人脸是红框选中时，表示有人脸无唇形。 <img src="'+b+'" alt="" title="null">图11 人脸预览框示意图</p></li><li><p>对话内容出现在右侧，只显示主交互人（人脸锁定）所说的话。</p></li></ol><p><img src="'+g+'" alt="" title="null"></p><p>图12 语音交互结果显示区域示意图</p><ol start="3"><li>多模态应用参数值，可根据不同的状态值判断交互异常原因</li></ol><p><img src="'+f+'" alt="" title="null"></p><p>图13 多模态应用参数值示意图</p><h2 id="标准使用模式" tabindex="-1">标准使用模式 <a class="header-anchor" href="#标准使用模式" aria-label="Permalink to &quot;标准使用模式&quot;">​</a></h2><h3 id="回采接线说明" tabindex="-1">回采接线说明 <a class="header-anchor" href="#回采接线说明" aria-label="Permalink to &quot;回采接线说明&quot;">​</a></h3><p>为了实现设备播音过程中，设备播音不被麦克风收集，实现实时打断交互，必须接回采线。回采接入有以下两种方式</p><ul><li>方式1：使用3588s板载功放，可直接通过3.5mm耳机口将合成音频接入到声卡回采接口，板载功放默认支持8欧姆10瓦；</li><li>方式2：使用外置功放，需要接外置功放的一路信号到声卡板上的回采接口。</li></ul><h3 id="工作模式说明" tabindex="-1">工作模式说明 <a class="header-anchor" href="#工作模式说明" aria-label="Permalink to &quot;工作模式说明&quot;">​</a></h3><ul><li>工作模式1： <strong>作为AI工控机主机模式</strong></li></ul><p><img src="'+_+'" alt="" title="null"></p><p>图14 作为AI工控机主机模式示意图</p><ul><li>工作模式2： <strong>作为输出语音交互指令从机模式</strong></li></ul><p><img src="'+q+'" alt="" title="null"></p><p>图15 串口信息给到上位机示意图</p><ul><li>工作模式3： <strong>作为输出多模态降噪音频从机模式</strong></li></ul><p><img src="'+k+'" alt="" title="null"></p><p>图16 多模态降噪音频给上位机示意图</p><p>温馨提示</p><p>1、默认RK3588S主板上的3.5mm耳机口和speaker播出的是合成音频，需要把aiui.cfg mmps下面的play_mmsp改成true且play_mode改成user，即可只输出降噪音频。</p><p>2、一般大屏产品会使用自己的功放播音，需要从最终使用的功放处获取回采信号接入声卡主板；如果大屏无法提供最终使用的功放后音频作为回采信号，可通过RK3588S主板上3.5mm耳机口将功放信号接入声卡主板，作为兜底策略。</p><h1 id="高级配置与开发" tabindex="-1">高级配置与开发 <a class="header-anchor" href="#高级配置与开发" aria-label="Permalink to &quot;高级配置与开发&quot;">​</a></h1><h2 id="appid申请与配置" tabindex="-1">Appid申请与配置 <a class="header-anchor" href="#appid申请与配置" aria-label="Permalink to &quot;Appid申请与配置&quot;">​</a></h2><p>1.<strong>appid申请</strong> 讯飞RK3588S模组与讯飞AIUI深度融合，支持客户自己基于AIUI平台进行识别引擎，语义引擎，合成发音人等一系列配置。请前往<a href="https://aiui.xfyun.cn/" title="讯飞AIUI开放平台" target="_blank" rel="noreferrer">讯飞AIUI开放平台</a>注册，并获取appid等信息。</p><p><img src="'+x+'" alt="" title="null"></p><p>图17 appid信息获取示意图</p><p>2.<strong>adb环境准备</strong> 使用双头usb线，将靠近网口旁边的USB口和电脑USB连接。</p><p><img src="'+P+'" alt="23a78c5d8a482ab0303d725beaf71d69" title="null"></p><p>图18 USB调试接口实物图</p><ol start="3"><li><strong>更新appid</strong></li></ol><ul><li>adb pull /sdcard/AIUI/cfg/aiui.cfg</li><li>修改aiui.cfg中的appid和key参数，对应AIUI平台</li><li>修改后上传，adb push aiui.cfg /sdcard/AIUI/cfg/</li><li>重启设备生效，adb reboot</li></ul><h2 id="协议对接" tabindex="-1">协议对接 <a class="header-anchor" href="#协议对接" aria-label="Permalink to &quot;协议对接&quot;">​</a></h2><ol><li>多模态套件当从机使用时，对接模组的识别等信息可以通过websokect协议或者ttl串口的方式获取，其中ttl串口只可以获取文字信息，websocket可以获取文字信息+音视频信息。(注意3588S裸板是ttl接口，带外壳主机上是232接口)</li><li>多模态交互套件支持传输多模态降噪后音频，模组摄像头采集视频流，以及云端识别交互内容给上位机，可通过websocket对接。</li></ol><ul><li>**音频传输协议：**用于从套件获取经过多模态降噪处理后的纯净音频流，<a href="/hardware/rk3588-mm/audio-protocol.html" title="点击查看">点击查看</a></li><li>**视频传输协议：**用于从套件获取摄像头采集的实时视频流，<a href="/hardware/rk3588-mm/video-protocol.html" title="点击查看">点击查看</a></li><li>**识别语义传输协议：**用于接收云端返回的识别结果和语义理解数据，<a href="/hardware/rk3588-mm/semantic-protocol.html">点击查看</a></li></ul><h2 id="二次开发指南" tabindex="-1">二次开发指南 <a class="header-anchor" href="#二次开发指南" aria-label="Permalink to &quot;二次开发指南&quot;">​</a></h2><p>本套件支持深度二次开发。关于SDK接口说明、示例代码及更详细的开发文档，请联系我司技术支持或商务人员获取</p><h1 id="调试与故障排除" tabindex="-1">调试与故障排除 <a class="header-anchor" href="#调试与故障排除" aria-label="Permalink to &quot;调试与故障排除&quot;">​</a></h1><h2 id="日志获取与分析" tabindex="-1">日志获取与分析 <a class="header-anchor" href="#日志获取与分析" aria-label="Permalink to &quot;日志获取与分析&quot;">​</a></h2><p>图 19 音频存储adb示意图</p><ul><li>安装adb工具： <a href="/media/attachment/2026/01/adb_1.0.41.zip">【附件】adb_1.0.41.zip</a></li><li>当出现异常问题时，需要获取调试日志分析，重启设备开机后，执行如下操作 <ul><li>打开cmd终端，执行adb logcat &gt; 123.txt</li><li>复现问题，等待10s</li><li>cmd终端执行ctrl+c 结束，日志生成在当前目录，把日志(123.txt)发回讯飞检查</li></ul></li></ul><h2 id="获取本地音频、图像" tabindex="-1">获取本地音频、图像 <a class="header-anchor" href="#获取本地音频、图像" aria-label="Permalink to &quot;获取本地音频、图像&quot;">​</a></h2><ul><li>adb shell</li><li>修改配置文件： busybox vi /sdcard/AIUI/mmsp/cfg/mmsp.cfg [将save_datalog取值改为1(存唇形和音频) 或 2（存原始图和音频)]</li></ul><p>⚠警告</p><p>存30秒即可，不可存太多，1分钟接近1个G****，存储文件极大，仅建议调试时短时开启，完成后务必改回0，否则可能导致存储空间耗尽和设备卡死。</p><ul><li>如果shell乱码，可以将配置文件导出到本地修改，然后push进去</li><li>重启设备：adb reboot</li><li>音频会存储在/sdcard/AIUI/mmsp/data目录下，每次交互会产生新的音频</li></ul><p><img src="'+I+'" alt="" title="null"></p><p>图19 音频存储adb示意图</p><ul><li>将音频拉到本地：adb pull sdcard/AIUI/mmsp/data</li><li>音频说明：可以将音频文件添加.pcm后缀名，使用Adobe_Audition打开查看。</li></ul><p>音频软件使用教程：<a href="https://www.yuque.com/iflyaiui/zzoolv/acykkh?singleDoc#" target="_blank" rel="noreferrer">https://www.yuque.com/iflyaiui/zzoolv/acykkh?singleDoc#</a> 《音频分析软件-Audition》</p><p><img src="'+A+'" alt="" title="null"></p><p>图20 存储音频说明图</p><h2 id="_6-3常见问题汇总" tabindex="-1">6.3常见问题汇总 <a class="header-anchor" href="#_6-3常见问题汇总" aria-label="Permalink to &quot;6.3常见问题汇总&quot;">​</a></h2><p><strong>如果您有以下问题需要解决，请访问相关文档查看，<a href="https://www.yuque.com/aiui/zzoolv/cpz9wb09lw6fgcv7" title="点击查看" target="_blank" rel="noreferrer">点击访问</a></strong></p><ol><li>HDMI投屏更改分辨率方法</li><li>更改板载功放功率</li><li>默认声音输出说明</li><li>关于客户二次开发，禁止应用弹框的问题方法</li><li>回采接入方式</li><li>关于3588S当主机使用时的虚拟人demo使用说明</li><li>设置静态IP</li><li>设置定制开关机</li><li>客户二次开发，需要获取系统权限</li></ol><h1 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h1><p>我们为客户提供全面、及时的技术支持，确保开发流程顺畅无忧。</p><ul><li>**技术支持：**如需帮助，请通过以下方式联系我们：</li><li><strong>技术支持邮箱：</strong><a href="mailto:support@iflytek.com" target="_blank" rel="noreferrer">support@iflytek.com</a></li><li><strong>官方网站：</strong><a href="https://aiui.xfyun.cn/" target="_blank" rel="noreferrer">https://aiui.xfyun.cn/</a></li></ul>',113)])])}const K=t(S,[["render",w]]);export{v as __pageData,K as default};
